import React from 'react';

const OnlineUsers = ({ users }) => {
  return (
    <div className="online-members-panel">
      <div className="online-members-title">Active Users ({users.length})</div>
      <div className="members-list">
        {users.length === 0 ? (
          <div style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>No users online</div>
        ) : (
          users.map((u, i) => (
            <div key={u.userId || i} className="member-card">
              <div className="avatar-circle" style={{ width: '30px', height: '30px', fontSize: '0.85rem' }}>
                {u.username.substring(0, 2).toUpperCase()}
              </div>
              <span className="member-name">{u.username}</span>
              <span className="status-dot"></span>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default OnlineUsers;
